public class AssetsAssetThemeRelController extends BaseController {    @Resource    private IAssetsAssetThemeRelService AssetsAssetThemeRelService;    @Operation(summary = "查询数据资产-主题关联关系列表")    @PreAuthorize("@ss.hasPermi('da:assetThemeRel:list')")    @GetMapping("/list")    public CommonResult<PageResult<AssetsAssetThemeRelRespVO>> list(AssetsAssetThemeRelPageReqVO AssetsAssetThemeRel) {        PageResult<AssetsAssetThemeRelDO> page = AssetsAssetThemeRelService.getDaAssetThemeRelPage(AssetsAssetThemeRel);        return CommonResult.success(BeanUtils.toBean(page, AssetsAssetThemeRelRespVO.class));    }    @Operation(summary = "导出数据资产-主题关联关系列表")    @PreAuthorize("@ss.hasPermi('da:assetThemeRel:export')")    @Log(title = "数据资产-主题关联关系", businessType = BusinessType.EXPORT)    @PostMapping("/export")    public void export(HttpServletResponse response, AssetsAssetThemeRelPageReqVO exportReqVO) {        exportReqVO.setPageSize(PageParam.PAGE_SIZE_NONE);        List<AssetsAssetThemeRelDO> list = (List<AssetsAssetThemeRelDO>) AssetsAssetThemeRelService.getDaAssetThemeRelPage(exportReqVO).getRows();        ExcelUtil<AssetsAssetThemeRelRespVO> util = new ExcelUtil<>(AssetsAssetThemeRelRespVO.class);        util.exportExcel(response, AssetsAssetThemeRelConvert.INSTANCE.convertToRespVOList(list), "应用管理数据");    }    @Operation(summary = "导入数据资产-主题关联关系列表")    @PreAuthorize("@ss.hasPermi('da:assetThemeRel:import')")    @Log(title = "数据资产-主题关联关系", businessType = BusinessType.IMPORT)    @PostMapping("/importData")    public AjaxResult importData(MultipartFile file, boolean updateSupport) throws Exception {        ExcelUtil<AssetsAssetThemeRelRespVO> util = new ExcelUtil<>(AssetsAssetThemeRelRespVO.class);        List<AssetsAssetThemeRelRespVO> importExcelList = util.importExcel(file.getInputStream());        String operName = getUsername();        String message = AssetsAssetThemeRelService.importDaAssetThemeRel(importExcelList, updateSupport, operName);        return success(message);    }    @Operation(summary = "获取数据资产-主题关联关系详细信息")    @PreAuthorize("@ss.hasPermi('da:assetThemeRel:query')")    @GetMapping(value = "/{id}")    public CommonResult<AssetsAssetThemeRelRespVO> getInfo(@PathVariable("id") Long id) {        AssetsAssetThemeRelDO AssetsAssetThemeRelDO = AssetsAssetThemeRelService.getDaAssetThemeRelById(id);        return CommonResult.success(BeanUtils.toBean(AssetsAssetThemeRelDO, AssetsAssetThemeRelRespVO.class));    }    @Operation(summary = "新增数据资产-主题关联关系")    @PreAuthorize("@ss.hasPermi('da:assetThemeRel:add')")    @Log(title = "数据资产-主题关联关系", businessType = BusinessType.INSERT)    @PostMapping    public CommonResult<Long> add(@Valid @RequestBody AssetsAssetThemeRelSaveReqVO AssetsAssetThemeRel) {        AssetsAssetThemeRel.setCreatorId(getUserId());        AssetsAssetThemeRel.setCreateBy(getNickName());        AssetsAssetThemeRel.setCreateTime(DateUtil.date());        return CommonResult.toAjax(AssetsAssetThemeRelService.createDaAssetThemeRel(AssetsAssetThemeRel));    }    @Operation(summary = "修改数据资产-主题关联关系")    @PreAuthorize("@ss.hasPermi('da:assetThemeRel:edit')")    @Log(title = "数据资产-主题关联关系", businessType = BusinessType.UPDATE)    @PutMapping    public CommonResult<Integer> edit(@Valid @RequestBody AssetsAssetThemeRelSaveReqVO AssetsAssetThemeRel) {        AssetsAssetThemeRel.setUpdatorId(getUserId());        AssetsAssetThemeRel.setUpdateBy(getNickName());        AssetsAssetThemeRel.setUpdateTime(DateUtil.date());        return CommonResult.toAjax(AssetsAssetThemeRelService.updateDaAssetThemeRel(AssetsAssetThemeRel));    }    @Operation(summary = "删除数据资产-主题关联关系")    @PreAuthorize("@ss.hasPermi('da:assetThemeRel:remove')")    @Log(title = "数据资产-主题关联关系", businessType = BusinessType.DELETE)    @DeleteMapping("/{ids}")    public CommonResult<Integer> remove(@PathVariable Long[] ids) {        return CommonResult.toAjax(AssetsAssetThemeRelService.removeDaAssetThemeRel(Arrays.asList(ids)));    }}